import type { Model, Enum, Union, Program } from "@typespec/compiler";

/** Symbol used by $specodec decorator — shared between decorator and accessor. */
export const specodecKey = Symbol.for("specodec:model");

/**
 * Returns true if the given model, enum, or union has been decorated with @specodec.
 */
export function isSpecodecType(program: Program, type: Model | Enum | Union): boolean {
  return program.stateSet(specodecKey).has(type);
}

/** @deprecated Use isSpecodecType instead. */
export const isSpecodecModel = isSpecodecType;
